[CmdletBinding()]
param(
    [string]$InstallPfad = "$env:USERPROFILE\Gutachten-Manager",
    [switch]$DryRun
)

Set-StrictMode -Off
$ErrorActionPreference = 'Stop'
$ProgressPreference    = 'SilentlyContinue'

# ==============================================================================
# KONSTANTEN
# ==============================================================================

$SCRIPT_VERSION = '2026.3.1'
$LOG_DATEI      = Join-Path $env:TEMP 'gutachten-manager-setup.log'
$script:TmpDir  = Join-Path $env:TEMP ("gm_setup_" + (Get-Random))

# ==============================================================================
# LOGGING  (Konsole + Datei)
# ==============================================================================

function Write-Log {
    param(
        [Parameter(Mandatory)][string]$Msg,
        [ValidateSet('INFO','OK','WARN','FEHLER','SCHRITT')][string]$Ebene = 'INFO'
    )
    $ts   = Get-Date -Format 'yyyy-MM-dd HH:mm:ss'
    $line = "[$ts] [$($Ebene.PadRight(6))] $Msg"
    Add-Content -Path $LOG_DATEI -Value $line -Encoding UTF8 -ErrorAction SilentlyContinue

    switch ($Ebene) {
        'OK'      { Write-Host "   [OK]  $Msg" -ForegroundColor Green  }
        'WARN'    { Write-Host "   [!]   $Msg" -ForegroundColor Yellow }
        'FEHLER'  { Write-Host "   [ERR] $Msg" -ForegroundColor Red    }
        'SCHRITT' { Write-Host "`n   >>> $Msg" -ForegroundColor Cyan
                    Write-Host "   $('─' * 60)" -ForegroundColor DarkGray }
        default   { Write-Host "         $Msg" -ForegroundColor Gray   }
    }
}

function Write-Schritt([int]$n, [string]$text) {
    Write-Log "[Schritt $n/8] $text" -Ebene SCHRITT
}

function Write-Banner {
    Clear-Host
    $title = "  GUTACHTEN-MANAGER  v$SCRIPT_VERSION  --  INSTALLER"
    Write-Host ""
    Write-Host ("  " + "=" * 62) -ForegroundColor Cyan
    Write-Host "  $title" -ForegroundColor Cyan
    Write-Host "  Log: $LOG_DATEI" -ForegroundColor DarkGray
    if ($DryRun) { Write-Host "  *** DRY-RUN MODUS -- keine Aenderungen ***" -ForegroundColor Magenta }
    Write-Host ("  " + "=" * 62) -ForegroundColor Cyan
    Write-Host ""
}

function Pause-Key([string]$Msg = "Beliebige Taste druecken...") {
    Write-Host "`n  >> $Msg" -ForegroundColor DarkCyan
    try { $null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown") } catch { Read-Host | Out-Null }
}

# ==============================================================================
# HILFSFUNKTIONEN
# ==============================================================================

function Test-Administrator {
    $principal = [Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()
    return $principal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
}

function Set-ExecutionPolicyBeiNot {
    $policy = Get-ExecutionPolicy -Scope Process -ErrorAction SilentlyContinue
    if ($policy -in @('Restricted', 'AllSigned')) {
        Set-ExecutionPolicy Bypass -Scope Process -Force
        Write-Log "ExecutionPolicy auf Bypass gesetzt (nur diese Sitzung)" -Ebene WARN
    }
}

function Test-Speicherplatz([string]$Pfad, [int]$MinGB = 6) {
    try {
        $drive  = (Split-Path -Qualifier $Pfad).TrimEnd(':')
        $disk   = Get-PSDrive $drive -ErrorAction Stop
        $freiGB = [math]::Round($disk.Free / 1GB, 1)
        if ($freiGB -lt $MinGB) {
            Write-Log "Zu wenig Speicher: $freiGB GB frei, $MinGB GB benoetigt" -Ebene FEHLER
            return $false
        }
        Write-Log "Speicherplatz: $freiGB GB frei (Mindestanforderung: $MinGB GB)" -Ebene OK
        return $true
    } catch {
        Write-Log "Speicherplatz konnte nicht geprueft werden: $_" -Ebene WARN
        return $true  # im Zweifelsfall fortfahren
    }
}

# ==============================================================================
# RETRY-WRAPPER  (exponentielles Backoff)
# ==============================================================================

function Invoke-MitRetry {
    param(
        [Parameter(Mandatory)][scriptblock]$Aktion,
        [string]$Beschreibung  = 'Operation',
        [int]   $MaxVersuche   = 5,
        [int[]] $WarteSekunden = @(2, 5, 10, 20, 40)
    )
    $versuch = 0
    while ($true) {
        $versuch++
        try {
            return (& $Aktion)
        } catch {
            if ($versuch -ge $MaxVersuche) {
                Write-Log "$Beschreibung fehlgeschlagen nach $MaxVersuche Versuchen: $_" -Ebene FEHLER
                throw
            }
            $wait = if ($versuch -le $WarteSekunden.Count) { $WarteSekunden[$versuch - 1] } else { 40 }
            Write-Log "[$Beschreibung] Versuch $versuch/$MaxVersuche fehlgeschlagen. Warte ${wait}s..." -Ebene WARN
            Start-Sleep $wait
        }
    }
}

# ==============================================================================
# DOWNLOAD  (mit Retry + Validierung)
# ==============================================================================

function Get-Datei {
    param(
        [Parameter(Mandatory)][string]$Url,
        [Parameter(Mandatory)][string]$Ziel,
        [Parameter(Mandatory)][string]$Name,
        [int]$MinMB = 0
    )
    Invoke-MitRetry -Beschreibung "Download $Name" -Aktion {
        Write-Log "Lade: $Name"
        Write-Log "URL:  $Url"

        # Methode 1: WebClient
        try {
            $wc = New-Object System.Net.WebClient
            $wc.Headers['User-Agent'] = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
            $wc.Headers['Accept']     = '*/*'
            $wc.DownloadFile($Url, $Ziel)
        } catch {
            # Methode 2: BITS (besser fuer grosse Dateien)
            Write-Log "WebClient fehlgeschlagen, versuche BITS..." -Ebene WARN
            Remove-Item $Ziel -Force -ErrorAction SilentlyContinue
            Import-Module BitsTransfer -ErrorAction Stop
            Start-BitsTransfer -Source $Url -Destination $Ziel -DisplayName $Name -ErrorAction Stop
        }

        # Validierung
        if (-not (Test-Path $Ziel)) {
            throw "Datei nicht vorhanden nach Download: $Ziel"
        }
        $sizeMB = [math]::Round((Get-Item $Ziel).Length / 1MB, 1)
        if ($sizeMB -lt $MinMB) {
            throw "Datei zu klein: $sizeMB MB (erwartet >$MinMB MB) -- Download unvollstaendig"
        }
        Write-Log "$Name heruntergeladen ($sizeMB MB)" -Ebene OK
    }
}

# ==============================================================================
# MODUL: WSL2 INSTALLIEREN
# ==============================================================================

function Install-WSL2 {
    Write-Log "Pruefe WSL2..."

    # Bereits installiert?
    try {
        $wslOut = (wsl --version 2>&1) -join ' '
        if ($LASTEXITCODE -eq 0 -and $wslOut -match 'WSL') {
            Write-Log "WSL2 bereits installiert: $($wslOut -replace '\s+', ' ')" -Ebene OK
            return
        }
    } catch {}

    if ($DryRun) { Write-Log "[DryRun] WSL2-Installation uebersprungen" -Ebene WARN; return }

    Write-Log "Richte WSL2 ein..."

    # Virtual Machine Platform aktivieren
    Write-Log "Aktiviere Virtual Machine Platform..."
    $r = Start-Process dism.exe `
        -ArgumentList '/online /enable-feature /featurename:VirtualMachinePlatform /all /norestart' `
        -Wait -PassThru -WindowStyle Hidden
    if ($r.ExitCode -notin @(0, 3010)) {
        Write-Log "VirtualMachinePlatform ExitCode: $($r.ExitCode) -- evtl. Neustart erforderlich" -Ebene WARN
    } else {
        Write-Log "Virtual Machine Platform aktiviert (ExitCode: $($r.ExitCode))" -Ebene OK
    }

    # WSL-Feature (nur vor Windows 11)
    $build = [int](Get-CimInstance Win32_OperatingSystem).BuildNumber
    if ($build -lt 22000) {
        Write-Log "Aktiviere Windows-Subsystem-Linux..."
        $r2 = Start-Process dism.exe `
            -ArgumentList '/online /enable-feature /featurename:Microsoft-Windows-Subsystem-Linux /all /norestart' `
            -Wait -PassThru -WindowStyle Hidden
        if ($r2.ExitCode -notin @(0, 3010)) {
            Write-Log "WSL-Feature ExitCode: $($r2.ExitCode)" -Ebene WARN
        }
    }

    # WSL2 Kernel-Update herunterladen + installieren
    $msi = Join-Path $script:TmpDir 'wsl_update.msi'
    Get-Datei `
        'https://wslstorestorage.blob.core.windows.net/wslblob/wsl_update_x64.msi' `
        $msi 'WSL2 Kernel-Update' -MinMB 1

    Write-Log "Installiere WSL2 Kernel..."
    $r3 = Start-Process msiexec.exe -ArgumentList "/i `"$msi`" /quiet /norestart" -Wait -PassThru
    if ($r3.ExitCode -notin @(0, 3010)) {
        throw "WSL2-Kernel-MSI fehlgeschlagen (ExitCode: $($r3.ExitCode))"
    }
    Write-Log "WSL2 Kernel installiert (ExitCode: $($r3.ExitCode))" -Ebene OK

    # WSL2 als Standard setzen
    try {
        wsl --set-default-version 2 2>&1 | Out-Null
        Write-Log "WSL2 als Standard-Version gesetzt" -Ebene OK
    } catch {
        Write-Log "WSL2 Standard konnte nicht gesetzt werden: $_" -Ebene WARN
    }

    # Verifikation
    try {
        $verify = (wsl --version 2>&1) -join ' '
        if ($LASTEXITCODE -eq 0) {
            Write-Log "WSL2 verifiziert" -Ebene OK
        } else {
            Write-Log "WSL2 Verifikation: Neustart des Rechners empfohlen" -Ebene WARN
        }
    } catch {
        Write-Log "WSL2 Verifikation: $_" -Ebene WARN
    }
}

# ==============================================================================
# MODUL: DOCKER DESKTOP INSTALLIEREN
# ==============================================================================

function Install-Docker {
    Write-Log "Pruefe Docker Desktop..."

    # Bereits installiert?
    $dockerOk = $false
    @(
        'C:\Program Files\Docker\Docker\Docker Desktop.exe',
        'C:\Program Files\Docker\Docker\resources\bin\docker.exe'
    ) | ForEach-Object { if (Test-Path $_) { $dockerOk = $true } }

    if (-not $dockerOk) {
        try { docker --version 2>&1 | Out-Null; if ($LASTEXITCODE -eq 0) { $dockerOk = $true } } catch {}
    }

    if ($dockerOk) {
        Write-Log "Docker Desktop bereits installiert" -Ebene OK
        return
    }

    if ($DryRun) { Write-Log "[DryRun] Docker-Installation uebersprungen" -Ebene WARN; return }

    Write-Log "Lade Docker Desktop herunter (~600 MB) -- bitte warten..." -Ebene WARN

    $installer  = Join-Path $script:TmpDir 'DockerDesktopInstaller.exe'
    $downloaded = $false
    foreach ($url in @(
        'https://desktop.docker.com/win/main/amd64/Docker%20Desktop%20Installer.exe',
        'https://desktop.docker.com/win/stable/amd64/Docker%20Desktop%20Installer.exe'
    )) {
        try {
            Get-Datei $url $installer 'Docker Desktop' -MinMB 100
            $downloaded = $true
            break
        } catch {
            Write-Log "URL fehlgeschlagen: $url" -Ebene WARN
        }
    }

    if (-not $downloaded) {
        throw "Docker Desktop konnte nicht heruntergeladen werden.`nBitte manuell installieren: https://docs.docker.com/desktop/install/windows-install/"
    }

    Write-Log "Installiere Docker Desktop (3-8 Minuten)..."
    $r = Start-Process $installer `
        -ArgumentList 'install --quiet --accept-license --backend=wsl-2' `
        -Wait -PassThru
    if ($r.ExitCode -notin @(0, 3010)) {
        throw "Docker Desktop Installation fehlgeschlagen (ExitCode: $($r.ExitCode))"
    }
    Write-Log "Docker Desktop installiert (ExitCode: $($r.ExitCode))" -Ebene OK

    if ($r.ExitCode -eq 3010) {
        Write-Log "Neustart empfohlen -- Installation wird fortgesetzt" -Ebene WARN
    }

    # PATH in aktueller Sitzung aktualisieren
    $machinePath = [Environment]::GetEnvironmentVariable('PATH', 'Machine')
    $userPath    = [Environment]::GetEnvironmentVariable('PATH', 'User')
    $env:PATH    = "$machinePath;$userPath"
    Write-Log "PATH aktualisiert" -Ebene OK
}

# ==============================================================================
# MODUL: DOCKER ENGINE BEREIT WARTEN
# ==============================================================================

function Wait-DockerBereit {
    param([int]$MaxSekunden = 180)

    # Docker Desktop starten falls nicht aktiv
    $dockerApp = 'C:\Program Files\Docker\Docker\Docker Desktop.exe'
    if ((Test-Path $dockerApp) -and -not (Get-Process 'Docker Desktop' -ErrorAction SilentlyContinue)) {
        Write-Log "Starte Docker Desktop..."
        if (-not $DryRun) { Start-Process $dockerApp }
    }

    if ($DryRun) {
        Write-Log "[DryRun] Docker-Wait uebersprungen" -Ebene WARN
        return $true
    }

    Write-Log "Warte auf Docker Engine (max. $MaxSekunden Sekunden)..."
    $elapsed = 0
    while ($elapsed -lt $MaxSekunden) {
        try {
            $info = docker info 2>&1
            if ($LASTEXITCODE -eq 0 -and ($info -join ' ') -match 'Server Version') {
                Write-Host ""
                $serverVer = (($info | Where-Object { $_ -match 'Server Version' }) -replace '.*Server Version:\s*','').Trim()
                Write-Log "Docker Engine bereit (Server Version: $serverVer)" -Ebene OK
                return $true
            }
        } catch {}
        $elapsed += 5
        Start-Sleep 5
        Write-Host '.' -NoNewline -ForegroundColor DarkGray
    }
    Write-Host ""
    Write-Log "Docker Engine nach $MaxSekunden Sekunden nicht bereit" -Ebene FEHLER
    return $false
}

# ==============================================================================
# MODUL: PROGRAMMCODE ENTPACKEN
# ==============================================================================

function Expand-Paket {
    param([string]$Ziel)

    Write-Log "Dekodiere eingebettetes Paket (195 Dateien)..."
    if ($DryRun) { Write-Log "[DryRun] Entpacken uebersprungen" -Ebene WARN; return }

    # --- EINGEBETTETER QUELLCODE (Base64-ZIP) ---------------------------------
    $B64 = ""
    # --- ENDE EINGEBETTETER QUELLCODE -----------------------------------------

    $bytes = [Convert]::FromBase64String($B64)
    if ($bytes.Length -lt 1000) { throw "Eingebettetes Paket beschaedigt (zu klein)" }

    $zipPfad = Join-Path $script:TmpDir 'gutachten-manager.zip'
    [IO.File]::WriteAllBytes($zipPfad, $bytes)
    Write-Log "Paket dekodiert ($([math]::Round($bytes.Length/1KB)) KB)" -Ebene OK

    # Zielverzeichnis
    if (Test-Path $Ziel) {
        Write-Log "Verzeichnis existiert -- Dateien werden aktualisiert: $Ziel" -Ebene WARN
    } else {
        New-Item -ItemType Directory -Path $Ziel -Force | Out-Null
        Write-Log "Verzeichnis erstellt: $Ziel" -Ebene OK
    }

    Write-Log "Entpacke Dateien..."
    Expand-Archive -Path $zipPfad -DestinationPath $script:TmpDir -Force

    $zipRoot = Get-ChildItem $script:TmpDir -Directory |
               Where-Object { $_.FullName -ne $script:TmpDir } |
               Select-Object -First 1
    if (-not $zipRoot) { throw "ZIP-Struktur ungueltig -- kein Unterordner gefunden" }

    Get-ChildItem $zipRoot.FullName | Copy-Item -Destination $Ziel -Recurse -Force

    $anzahl = (Get-ChildItem $Ziel -Recurse -File -ErrorAction SilentlyContinue).Count
    Write-Log "$anzahl Dateien entpackt nach: $Ziel" -Ebene OK
}

# ==============================================================================
# MODUL: KONFIGURATION ERSTELLEN
# ==============================================================================

function Initialize-Konfiguration {
    param([string]$InstallPfad)

    $envPfad     = Join-Path $InstallPfad '.env'
    $envBeispiel = Join-Path $InstallPfad '.env.example'

    if (Test-Path $envPfad) {
        Write-Log ".env bereits vorhanden -- unveraendert" -Ebene OK
        return
    }
    if ($DryRun) { Write-Log "[DryRun] .env erstellen uebersprungen" -Ebene WARN; return }

    if (Test-Path $envBeispiel) {
        Copy-Item $envBeispiel $envPfad
        Write-Log ".env aus .env.example erstellt" -Ebene OK
    } else {
        @"
NODE_ENV=production
PORT=4000
POSTGRES_HOST=db
POSTGRES_PORT=5432
POSTGRES_DB=gutachten_manager
POSTGRES_USER=gutachten_user
POSTGRES_PASSWORD=GutachtenManager2024!
DATABASE_URL=postgresql://gutachten_user:GutachtenManager2024!@db:5432/gutachten_manager
JWT_SECRET=GutachtenManagerJWT2024ChangeInProduction
UPLOAD_MAX_SIZE=52428800
LOG_LEVEL=info
"@ | Set-Content $envPfad -Encoding UTF8
        Write-Log ".env mit Standard-Konfiguration erstellt" -Ebene OK
    }

    # Berechtigungen absichern
    try {
        $acl  = Get-Acl $envPfad
        $acl.SetAccessRuleProtection($true, $false)
        $rule = New-Object Security.AccessControl.FileSystemAccessRule(
            $env:USERNAME, 'FullControl', 'Allow')
        $acl.AddAccessRule($rule)
        Set-Acl $envPfad $acl
        Write-Log ".env-Berechtigungen gesetzt (nur $env:USERNAME)" -Ebene OK
    } catch {
        Write-Log ".env-Berechtigungen konnten nicht gesetzt werden: $_" -Ebene WARN
    }
}

# ==============================================================================
# MODUL: APP HEALTH CHECK
# ==============================================================================

function Wait-AppBereit {
    param([int]$MaxSekunden = 300)

    if ($DryRun) { Write-Log "[DryRun] Healthcheck uebersprungen" -Ebene WARN; return $true }

    Write-Log "Warte auf Anwendung (max. $([math]::Round($MaxSekunden/60,1)) Minuten)..."
    $elapsed = 0
    while ($elapsed -lt $MaxSekunden) {
        try {
            $r = Invoke-WebRequest 'http://localhost/api/v1/health' `
                -UseBasicParsing -TimeoutSec 5 -ErrorAction Stop
            if ($r.StatusCode -eq 200) {
                # JSON-Validierung
                try {
                    $json   = $r.Content | ConvertFrom-Json -ErrorAction Stop
                    $status = if ($json.data.status) { $json.data.status }
                              elseif ($json.status)  { $json.status }
                              else { 'ok' }
                    Write-Host ""
                    Write-Log "API bereit | HTTP 200 | status=$status" -Ebene OK
                } catch {
                    Write-Host ""
                    Write-Log "API bereit | HTTP 200 (kein JSON-Body)" -Ebene OK
                }
                return $true
            }
        } catch {}
        $elapsed += 5
        Start-Sleep 5
        Write-Host '.' -NoNewline -ForegroundColor DarkGray
    }
    Write-Host ""
    Write-Log "Anwendung nach $MaxSekunden Sekunden nicht erreichbar" -Ebene WARN
    return $false
}

# ==============================================================================
# MODUL: VERKNUEPFUNGEN + SHELL-TOOL
# ==============================================================================

function Install-Verknuepfungen {
    param([string]$InstallPfad)

    if ($DryRun) { Write-Log "[DryRun] Verknuepfungen uebersprungen" -Ebene WARN; return }

    $desktop = [Environment]::GetFolderPath('Desktop')
    $wsh     = New-Object -ComObject WScript.Shell

    $kuerzel = @(
        @{ Name='Gutachten-Manager STARTEN'; Datei='STARTEN.bat'; Icon='shell32.dll,137'; Beschr='Starten' },
        @{ Name='Gutachten-Manager BEENDEN'; Datei='BEENDEN.bat'; Icon='shell32.dll,131'; Beschr='Stoppen' },
        @{ Name='Gutachten-Manager STATUS';  Datei='STATUS.bat';  Icon='shell32.dll,21';  Beschr='Status'  }
    )

    foreach ($k in $kuerzel) {
        try {
            $lnk = $wsh.CreateShortcut((Join-Path $desktop "$($k.Name).lnk"))
            $lnk.TargetPath       = Join-Path $InstallPfad $k.Datei
            $lnk.WorkingDirectory = $InstallPfad
            $lnk.Description      = "Gutachten-Manager $($k.Beschr)"
            $lnk.IconLocation     = "C:\Windows\System32\$($k.Icon)"
            $lnk.Save()
            Write-Log "Verknuepfung: $($k.Name)" -Ebene OK
        } catch {
            Write-Log "Verknuepfung '$($k.Name)' fehlgeschlagen: $_" -Ebene WARN
        }
    }

    # gm-Befehl in PowerShell-Profil
    $gmPfad   = Join-Path $InstallPfad 'maintenance\gm.ps1'
    $profileDir = Split-Path $PROFILE
    if (-not (Test-Path $profileDir)) { New-Item -ItemType Directory -Path $profileDir -Force | Out-Null }
    if (-not (Test-Path $PROFILE))    { New-Item -ItemType File      -Path $PROFILE    -Force | Out-Null }

    $profilCode = @"

# Gutachten-Manager CLI (von Gutachten-Manager-Setup.ps1)
function gm { param([Parameter(ValueFromRemainingArguments)][string[]]`$args); & "$gmPfad" @args }
"@
    $profilInhalt = (Get-Content $PROFILE -Raw -ErrorAction SilentlyContinue) ?? ''
    if ($profilInhalt -notmatch 'Gutachten-Manager CLI') {
        Add-Content $PROFILE $profilCode -Encoding UTF8
        Write-Log "'gm'-Befehl in PowerShell-Profil registriert: $PROFILE" -Ebene OK
    } else {
        Write-Log "'gm'-Befehl bereits im Profil" -Ebene OK
    }

    # In aktueller Sitzung sofort aktiv
    if (Test-Path $gmPfad) {
        $gmPfadLocal = $gmPfad
        function global:gm { param([Parameter(ValueFromRemainingArguments)][string[]]$args); & $gmPfadLocal @args }
        Write-Log "'gm' in aktueller Sitzung aktiv" -Ebene OK
    }
}

# ==============================================================================
# MODUL: ANWENDUNG STARTEN
# ==============================================================================

function Start-Anwendung {
    param([string]$InstallPfad)

    if ($DryRun) { Write-Log "[DryRun] docker compose up uebersprungen" -Ebene WARN; return }

    Write-Log "Starte Docker-Build und Anwendung..."
    Write-Log "Beim ersten Start: ~10-20 Minuten (Abhaengigkeiten werden geladen)" -Ebene WARN

    $bau = Start-Process 'docker' `
        -ArgumentList 'compose up --build -d' `
        -WorkingDirectory $InstallPfad `
        -NoNewWindow -Wait -PassThru

    if ($bau.ExitCode -ne 0) {
        # Logs fuer Diagnose einsammeln
        $logs = docker compose logs --tail=50 2>&1 | Out-String
        Write-Log "docker compose logs (letzte 50 Zeilen):`n$logs" -Ebene FEHLER
        throw "docker compose up fehlgeschlagen (ExitCode: $($bau.ExitCode))`nLogs: $LOG_DATEI"
    }
    Write-Log "Docker-Build erfolgreich" -Ebene OK
}

# ==============================================================================
# CLEANUP (laeuft immer, auch bei Fehler)
# ==============================================================================

function Invoke-Cleanup {
    if (Test-Path $script:TmpDir) {
        Remove-Item $script:TmpDir -Recurse -Force -ErrorAction SilentlyContinue
        Write-Log "Temporaere Dateien geloescht" -Ebene INFO
    }
}

# ==============================================================================
# HAUPTPROGRAMM
# ==============================================================================

# --- Admin-Rechte pruefen ---
if (-not (Test-Administrator)) {
    Write-Host ""
    Write-Host "  FEHLER: Administrator-Rechte erforderlich!" -ForegroundColor Red
    Write-Host "  Rechtsklick auf die Datei -> 'Als Administrator ausfuehren'" -ForegroundColor Yellow
    Write-Host ""
    Pause-Key "Taste druecken zum Beenden."
    exit 1
}

# --- ExecutionPolicy ---
Set-ExecutionPolicyBeiNot

# --- Log starten ---
Write-Log "=== Gutachten-Manager Setup gestartet ==="
Write-Log "Version: $SCRIPT_VERSION | Benutzer: $env:USERNAME | Rechner: $env:COMPUTERNAME"
Write-Log "Installationspfad: $InstallPfad | DryRun: $DryRun"

# --- Banner ---
Write-Banner

New-Item -ItemType Directory -Path $script:TmpDir -Force | Out-Null

try {

    # ── SCHRITT 1: Windows pruefen ─────────────────────────────────────────
    Write-Schritt 1 "Systemanforderungen pruefen"

    $os    = Get-CimInstance Win32_OperatingSystem
    $build = [int]$os.BuildNumber
    Write-Log "Betriebssystem: $($os.Caption) (Build $build)"

    if ($build -lt 19041) {
        throw "Windows 10 Build 19041+ erforderlich. Aktuell: Build $build. Bitte Windows Update ausfuehren."
    }
    Write-Log "Windows kompatibel (Build $build)" -Ebene OK

    $virt = (Get-CimInstance Win32_ComputerSystem).HypervisorPresent
    if ($virt) { Write-Log "Virtualisierung verfuegbar" -Ebene OK }
    else       { Write-Log "Virtualisierung evtl. deaktiviert -- bitte im BIOS/UEFI aktivieren" -Ebene WARN }

    if (-not (Test-Speicherplatz $InstallPfad)) {
        throw "Unzureichender Speicherplatz. Mindestens 6 GB benoetigt."
    }

    # Benutzer-Bestaetigung
    Write-Host ""
    Write-Host "  Installationspfad : $InstallPfad" -ForegroundColor White
    Write-Host "  Log-Datei         : $LOG_DATEI"   -ForegroundColor Gray
    if ($DryRun) { Write-Host "  Modus             : DRY-RUN (keine Aenderungen)" -ForegroundColor Magenta }
    Write-Host ""
    Write-Log "ENTER zum Starten, Ctrl+C zum Abbrechen."
    Read-Host | Out-Null

    # ── SCHRITT 2: WSL2 ────────────────────────────────────────────────────
    Write-Schritt 2 "WSL2 pruefen und einrichten"
    Install-WSL2

    # ── SCHRITT 3: Docker Desktop ──────────────────────────────────────────
    Write-Schritt 3 "Docker Desktop pruefen und installieren"
    Install-Docker

    # ── SCHRITT 4: Dateien entpacken ───────────────────────────────────────
    Write-Schritt 4 "Programmcode entpacken (195 Dateien)"
    Expand-Paket -Ziel $InstallPfad

    # ── SCHRITT 5: Konfiguration ───────────────────────────────────────────
    Write-Schritt 5 "Konfiguration erstellen"
    Initialize-Konfiguration -InstallPfad $InstallPfad

    # ── SCHRITT 6: Verknuepfungen + Shell-Tool ─────────────────────────────
    Write-Schritt 6 "Desktop-Verknuepfungen und 'gm'-Befehl einrichten"
    Install-Verknuepfungen -InstallPfad $InstallPfad

    # ── SCHRITT 7: Docker starten ──────────────────────────────────────────
    Write-Schritt 7 "Docker Desktop starten und warten"
    $dockerBereit = Wait-DockerBereit -MaxSekunden 180
    if (-not $dockerBereit) {
        Write-Log "Docker nicht bereit. Bitte Docker Desktop manuell starten," -Ebene WARN
        Write-Log "dann Desktop-Verknuepfung 'Gutachten-Manager STARTEN' benutzen." -Ebene WARN
        Invoke-Cleanup
        Pause-Key "Taste druecken zum Beenden."
        exit 0
    }

    # ── SCHRITT 8: App bauen + starten ────────────────────────────────────
    Write-Schritt 8 "Docker-Images bauen und Anwendung starten"
    Set-Location $InstallPfad
    Start-Anwendung -InstallPfad $InstallPfad

    $appBereit = Wait-AppBereit -MaxSekunden 300

    # ── ABSCHLUSS ─────────────────────────────────────────────────────────
    Write-Banner
    Write-Log "=== Setup abgeschlossen ==="

    if ($appBereit) {
        Write-Host ("  " + "=" * 62) -ForegroundColor Green
        Write-Host "  INSTALLATION ERFOLGREICH ABGESCHLOSSEN!" -ForegroundColor Green
        Write-Host ("  " + "=" * 62) -ForegroundColor Green
        if (-not $DryRun) { Start-Process 'http://localhost' }
    } else {
        Write-Host ("  " + "=" * 62) -ForegroundColor Yellow
        Write-Host "  Setup abgeschlossen  --  App startet noch..." -ForegroundColor Yellow
        Write-Host "  Oeffnen Sie in 2-3 Minuten: http://localhost" -ForegroundColor White
        Write-Host ("  " + "=" * 62) -ForegroundColor Yellow
    }

    Write-Host ""
    Write-Host "  Adresse       :  http://localhost"              -ForegroundColor Cyan
    Write-Host "  Installiert   :  $InstallPfad"                  -ForegroundColor White
    Write-Host "  Log-Datei     :  $LOG_DATEI"                    -ForegroundColor Gray
    Write-Host ""
    Write-Host "  Desktop-Verknuepfungen:" -ForegroundColor White
    Write-Host "    Gutachten-Manager STARTEN  /  BEENDEN  /  STATUS" -ForegroundColor Gray
    Write-Host ""
    Write-Host "  PowerShell-Verwaltung (in jeder PS-Sitzung):" -ForegroundColor White
    Write-Host "    gm status | gm start | gm stop | gm logs | gm backup" -ForegroundColor Gray
    Write-Host "    gm restore | gm rebuild | gm update | gm help" -ForegroundColor Gray
    Write-Host ""

} catch {
    Write-Log "FEHLER: $_" -Ebene FEHLER
    Write-Host ""
    Write-Host "  INSTALLATION FEHLGESCHLAGEN" -ForegroundColor Red
    Write-Host "  Fehler   : $_"              -ForegroundColor Red
    Write-Host "  Log-Datei: $LOG_DATEI"      -ForegroundColor Yellow
    Write-Host ""
    Write-Host "  Bitte Log-Datei pruefen und erneut versuchen." -ForegroundColor Gray
    Invoke-Cleanup
    Pause-Key "Taste druecken zum Beenden."
    exit 1
} finally {
    Invoke-Cleanup
}

Pause-Key "Taste druecken zum Schliessen."
